import React, { useState, useRef, useEffect } from 'react';
import { Stage, Layer, Text, Image as KonvaImage, Transformer } from 'react-konva';
import useImage from 'use-image';
import { useCart } from '../context/AppContext';
import { Download, ShoppingCart, Layers, Type, Upload, Move } from 'lucide-react';

// --- IMAGE DRAG ---
const DraggableImage = ({ url, isSelected, onSelect, onChange }) => {
  const [img] = useImage(url);
  const shapeRef = useRef();
  const trRef = useRef();

  useEffect(() => {
    if (isSelected && trRef.current && shapeRef.current) {
      trRef.current.nodes([shapeRef.current]);
      trRef.current.getLayer().batchDraw();
    }
  }, [isSelected]);

  return (
    <>
      <KonvaImage
        image={img}
        ref={shapeRef}
        draggable
        onClick={onSelect}
        onTap={onSelect}
        width={150}
        height={150}
        x={100}
        y={100}
        onDragEnd={(e) => {
          onChange({ x: e.target.x(), y: e.target.y() });
        }}
        onTransformEnd={() => {
          const node = shapeRef.current;
          const scaleX = node.scaleX();
          const scaleY = node.scaleY();

          node.scaleX(1);
          node.scaleY(1);

          onChange({
            x: node.x(),
            y: node.y(),
            width: Math.max(50, node.width() * scaleX),
            height: Math.max(50, node.height() * scaleY),
          });
        }}
      />
      {isSelected && (
        <Transformer
          ref={trRef}
          boundBoxFunc={(oldBox, newBox) => {
            if (newBox.width < 50 || newBox.height < 50) return oldBox;
            return newBox;
          }}
        />
      )}
    </>
  );
};

// --- TEXTE DRAG ---
const DraggableText = ({ text, color, font, size, isSelected, onSelect, onChange }) => {
  const shapeRef = useRef();
  const trRef = useRef();

  useEffect(() => {
    if (isSelected && trRef.current && shapeRef.current) {
      trRef.current.nodes([shapeRef.current]);
      trRef.current.getLayer().batchDraw();
    }
  }, [isSelected]);

  return (
    <>
      <Text
        text={text}
        fill={color}
        fontFamily={font}
        fontSize={size}
        ref={shapeRef}
        draggable
        x={120}
        y={150}
        onClick={onSelect}
        onTap={onSelect}
        onDragEnd={(e) => onChange({ x: e.target.x(), y: e.target.y() })}
      />
      {isSelected && (
        <Transformer
          ref={trRef}
          enabledAnchors={['top-left', 'top-right', 'bottom-left', 'bottom-right']}
        />
      )}
    </>
  );
};

// --- MAIN ---
export default function Personnalisation() {
  const { addItem } = useCart();
  const [selectedId, setSelectedId] = useState(null);
  const [productColor, setProductColor] = useState('#FFFFFF');
  const [text, setText] = useState('VOTRE TEXTE');
  const [textColor, setTextColor] = useState('#000000');
  const [uploadedImg, setUploadedImg] = useState(null);
  const stageRef = useRef();

  const handleExport = () => {
    const uri = stageRef.current.toDataURL({ pixelRatio: 2 });
    const link = document.createElement('a');
    link.download = 'mon-design.png';
    link.href = uri;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div style={{ background: '#F0F2F5', minHeight: '100vh', fontFamily: 'Poppins, sans-serif' }}>

      {/* HEADER */}
      <div style={{
        background: '#0D0D0D',
        color: 'white',
        padding: '20px 40px',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <h1 style={{ fontSize: 20, fontWeight: 900 }}>
          STUDIO <span style={{ color: '#017BFE' }}>DESIGN</span>
        </h1>

        <div style={{ display: 'flex', gap: 12 }}>
          <button onClick={handleExport} style={btnDark}>
            <Download size={18} /> Exporter
          </button>

          <button onClick={() => addItem({ name: "Produit Custom", price: 15000 })} style={btnBlue}>
            <ShoppingCart size={18} /> Commander
          </button>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '350px 1fr', height: 'calc(100vh - 80px)' }}>

        {/* SIDEBAR */}
        <div style={{ background: 'white', borderRight: '1px solid #E5E7EB', padding: 30 }}>

          <h3 style={title}><Layers size={16} /> CONFIGURATION</h3>

          <div style={{ display: 'flex', gap: 10 }}>
            {['#FFFFFF', '#000000', '#017BFE', '#EF4444', '#02AB84'].map(c => (
              <div key={c} onClick={() => setProductColor(c)}
                style={{
                  width: 35,
                  height: 35,
                  borderRadius: '50%',
                  background: c,
                  border: productColor === c ? '3px solid #017BFE' : '1px solid #DDD',
                  cursor: 'pointer'
                }}
              />
            ))}
          </div>

          <h3 style={title}><Type size={16} /> TEXTE</h3>

          <input
            value={text}
            onChange={(e) => setText(e.target.value)}
            style={input}
          />

          <h3 style={title}><Upload size={16} /> IMAGE</h3>

          <input
            type="file"
            onChange={(e) => {
              const file = e.target.files[0];
              if (!file) return;

              const reader = new FileReader();
              reader.onload = () => setUploadedImg(reader.result);
              reader.readAsDataURL(file);
            }}
          />
        </div>

        {/* CANVAS */}
        <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <Stage width={400} height={450} ref={stageRef}
            onMouseDown={(e) => {
              if (e.target === e.target.getStage()) setSelectedId(null);
            }}
          >
            <Layer>

              {uploadedImg && (
                <DraggableImage
                  url={uploadedImg}
                  isSelected={selectedId === 'img'}
                  onSelect={() => setSelectedId('img')}
                  onChange={() => {}}
                />
              )}

              <DraggableText
                text={text}
                color={textColor}
                font="Arial"
                size={30}
                isSelected={selectedId === 'text'}
                onSelect={() => setSelectedId('text')}
                onChange={() => {}}
              />

            </Layer>
          </Stage>
        </div>
      </div>
    </div>
  );
}

// --- STYLES ---
const btnDark = {
  background: '#333',
  color: 'white',
  border: 'none',
  padding: '10px 20px',
  borderRadius: 12,
  cursor: 'pointer',
  display: 'flex',
  gap: 8,
  alignItems: 'center'
};

const btnBlue = {
  ...btnDark,
  background: '#017BFE'
};

const title = {
  marginTop: 20,
  fontSize: 14,
  fontWeight: 800,
  display: 'flex',
  gap: 8,
  alignItems: 'center'
};

const input = {
  width: '100%',
  padding: '10px',
  borderRadius: 10,
  border: '1px solid #DDD'
};
